   393→func (l *base) detectRunningOnAws() (ok bool, instanceID string, err error) {
   394→	if r := l.exec("type curl", noSudo); r.isSuccess() {
   395→		cmd := "curl --max-time 1 --noproxy 169.254.169.254 http://169.254.169.254/latest/meta-data/instance-id"
   396→		r := l.exec(cmd, noSudo)
   397→		if r.isSuccess() {
   398→			id := strings.TrimSpace(r.Stdout)
   399→			if !l.isAwsInstanceID(id) {
   400→				return false, "", nil
   401→			}
   402→			return true, id, nil
   403→		}
   404→
   405→		switch r.ExitStatus {
   406→		case 28, 7:
   407→			// Not running on AWS
   408→			//  7   Failed to connect to host.
   409→			// 28  operation timeout.
   410→			return false, "", nil
   411→		}
   412→	}
   413→
   414→	if r := l.exec("type wget", noSudo); r.isSuccess() {
   415→		cmd := "wget --tries=3 --timeout=1 --no-proxy -q -O - http://169.254.169.254/latest/meta-data/instance-id"
   416→		r := l.exec(cmd, noSudo)
   417→		if r.isSuccess() {
   418→			id := strings.TrimSpace(r.Stdout)
   419→			if !l.isAwsInstanceID(id) {
   420→				return false, "", nil
   421→			}
   422→			return true, id, nil
   423→		}
   424→
   425→		switch r.ExitStatus {
   426→		case 4, 8:
   427→			// Not running on AWS
   428→			// 4   Network failure
   429→			// 8   Server issued an error response.
   430→			return false, "", nil
   431→		}
   432→	}
   433→	return false, "", xerrors.Errorf(
   434→		"Failed to curl or wget to AWS instance metadata on %s. container: %s",
   435→		l.ServerInfo.ServerName, l.ServerInfo.Container.Name)
   436→}
   437→
   438→// http://docs.aws.amazon.com/AWSEC2/latest/UserGuide/resource-ids.html
   439→var awsInstanceIDPattern = regexp.MustCompile(`^i-[0-9a-f]+$`)
   440→
   441→func (l *base) isAwsInstanceID(str string) bool {
   442→	return awsInstanceIDPattern.MatchString(str)
   443→}
