   549→func (l *base) detectServiceName(pid string) (string, error) {
   550→	cmd := fmt.Sprintf("systemctl status --quiet --no-pager %s", pid)
   551→	r := l.exec(cmd, noSudo)
   552→	if !r.isSuccess() {
   553→		return "", xerrors.Errorf("Failed to stat %s: %s", cmd, r)
   554→	}
   555→	return l.parseSystemctlStatus(r.Stdout), nil
   556→}
