   859→func (l *base) detectScanDest() map[string][]string {
   860→	scanIPPortsMap := map[string][]string{}
   861→
   862→	for _, p := range l.osPackages.Packages {
   863→		if p.AffectedProcs == nil {
   864→			continue
   865→		}
   866→		for _, proc := range p.AffectedProcs {
   867→			if proc.ListenPortStats == nil {
   868→				continue
   869→			}
   870→			for _, port := range proc.ListenPortStats {
   871→				scanIPPortsMap[port.BindAddress] = append(scanIPPortsMap[port.BindAddress], port.Port)
   872→			}
   873→		}
   874→	}
   875→
   876→	scanDestIPPorts := map[string][]string{}
   877→	for addr, ports := range scanIPPortsMap {
   878→		if addr == "*" {
   879→			for _, addr := range l.ServerInfo.IPv4Addrs {
   880→				scanDestIPPorts[addr] = append(scanDestIPPorts[addr], ports...)
   881→			}
   882→		} else {
   883→			scanDestIPPorts[addr] = append(scanDestIPPorts[addr], ports...)
   884→		}
   885→	}
   886→
   887→	uniqScanDestIPPorts := map[string][]string{}
   888→	for i, scanDest := range scanDestIPPorts {
   889→		m := map[string]bool{}
   890→		for _, e := range scanDest {
   891→			if !m[e] {
   892→				m[e] = true
   893→				uniqScanDestIPPorts[i] = append(uniqScanDestIPPorts[i], e)
   894→			}
   895→		}
   896→	}
   897→
   898→	return uniqScanDestIPPorts
   899→}
