   961→func (l *base) execExternalPortScan(scanDestIPPorts map[string][]string) ([]string, error) {
   962→	portScanConf := l.getServerInfo().PortScan
   963→	l.log.Infof("Using Port Scanner: External Scanner(PATH: %s)", portScanConf.ScannerBinPath)
   964→	l.log.Infof("External Scanner Apply Options: Scan Techniques: %s, HasPrivileged: %t, Source Port: %s",
   965→		strings.Join(portScanConf.ScanTechniques, ","), portScanConf.HasPrivileged, portScanConf.SourcePort)
   966→	baseCmd := formatNmapOptionsToString(portScanConf)
   967→
   968→	listenIPPorts := []string{}
   969→
   970→	for ip, ports := range scanDestIPPorts {
   971→		if !isLocalExec(l.ServerInfo.Port, l.ServerInfo.Host) && net.ParseIP(ip).IsLoopback() {
   972→			continue
   973→		}
   974→
   975→		_, cancel := context.WithTimeout(context.Background(), 5*time.Minute)
   976→		defer cancel()
   977→
   978→		scanner, err := nmap.NewScanner(nmap.WithBinaryPath(portScanConf.ScannerBinPath))
   979→		if err != nil {
   980→			return []string{}, xerrors.Errorf("unable to create nmap scanner: %w", err)
   981→		}
   982→
   983→		scanTechnique, err := l.setScanTechniques()
   984→		if err != nil {
   985→			return []string{}, err
   986→		}
   987→		scanner.AddOptions(scanTechnique)
   988→
   989→		if portScanConf.HasPrivileged {
   990→			scanner.AddOptions(nmap.WithPrivileged())
   991→		} else {
   992→			scanner.AddOptions(nmap.WithUnprivileged())
   993→		}
   994→
   995→		if portScanConf.SourcePort != "" {
   996→			port, err := strconv.ParseUint(portScanConf.SourcePort, 10, 16)
   997→			if err != nil {
   998→				return []string{}, xerrors.Errorf("failed to strconv.ParseUint(%s, 10, 16) = %w", portScanConf.SourcePort, err)
   999→			}
  1000→			scanner.AddOptions(nmap.WithSourcePort(uint16(port)))
  1001→		}
  1002→
  1003→		cmd := []string{baseCmd}
  1004→		if strings.Contains(ip, ":") {
  1005→			scanner.AddOptions(nmap.WithTargets(ip[1:len(ip)-1]), nmap.WithPorts(ports...), nmap.WithIPv6Scanning())
  1006→			cmd = append(cmd, "-p", strings.Join(ports, ","), ip[1:len(ip)-1])
  1007→		} else {
  1008→			scanner.AddOptions(nmap.WithTargets(ip), nmap.WithPorts(ports...))
  1009→			cmd = append(cmd, "-p", strings.Join(ports, ","), ip)
  1010→		}
  1011→
  1012→		l.log.Debugf("Executing... %s", strings.Replace(strings.Join(cmd, " "), "\n", "", -1))
  1013→		result, warnings, err := scanner.Run()
  1014→		if err != nil {
  1015→			return []string{}, xerrors.Errorf("unable to run nmap scan: %w", err)
  1016→		}
  1017→
  1018→		if warnings != nil {
  1019→			l.log.Warnf("nmap scan warnings: %s", warnings)
  1020→		}
  1021→
  1022→		for _, host := range result.Hosts {
  1023→			if len(host.Ports) == 0 || len(host.Addresses) == 0 {
  1024→				continue
  1025→			}
  1026→
  1027→			for _, port := range host.Ports {
  1028→				if strings.Contains(string(port.Status()), string(nmap.Open)) {
  1029→					scanDest := fmt.Sprintf("%s:%d", ip, port.ID)
  1030→					listenIPPorts = append(listenIPPorts, scanDest)
  1031→				}
  1032→			}
  1033→		}
  1034→	}
  1035→
  1036→	return listenIPPorts, nil
  1037→}
  1038→
  1039→func formatNmapOptionsToString(conf *config.PortScanConf) string {
  1040→	cmd := []string{conf.ScannerBinPath}
  1041→	if len(conf.ScanTechniques) != 0 {
  1042→		for _, technique := range conf.ScanTechniques {
  1043→			cmd = append(cmd, "-"+technique)
  1044→		}
  1045→	}
  1046→
  1047→	if conf.SourcePort != "" {
  1048→		cmd = append(cmd, "--source-port "+conf.SourcePort)
  1049→	}
  1050→
  1051→	if conf.HasPrivileged {
  1052→		cmd = append(cmd, "--privileged")
  1053→	}
  1054→
  1055→	return strings.Join(cmd, " ")
  1056→}
  1057→
  1058→func (l *base) setScanTechniques() (func(*nmap.Scanner), error) {
  1059→	scanTechniques := l.getServerInfo().PortScan.GetScanTechniques()
  1060→
  1061→	if len(scanTechniques) == 0 {
  1062→		if l.getServerInfo().PortScan.HasPrivileged {
  1063→			return nmap.WithSYNScan(), nil
  1064→		}
  1065→		return nmap.WithConnectScan(), nil
  1066→	}
  1067→
  1068→	for _, technique := range scanTechniques {
  1069→		switch technique {
  1070→		case config.TCPSYN:
  1071→			return nmap.WithSYNScan(), nil
  1072→		case config.TCPConnect:
  1073→			return nmap.WithConnectScan(), nil
  1074→		case config.TCPACK:
  1075→			return nmap.WithACKScan(), nil
  1076→		case config.TCPWindow:
  1077→			return nmap.WithWindowScan(), nil
  1078→		case config.TCPMaimon:
  1079→			return nmap.WithMaimonScan(), nil
  1080→		case config.TCPNull:
  1081→			return nmap.WithTCPNullScan(), nil
  1082→		case config.TCPFIN:
  1083→			return nmap.WithTCPFINScan(), nil
  1084→		case config.TCPXmas:
  1085→			return nmap.WithTCPXmasScan(), nil
  1086→		}
  1087→	}
  1088→
  1089→	return nil, xerrors.Errorf("Failed to setScanTechniques. There is an unsupported option in ScanTechniques.")
  1090→}
  1091→
  1092→func (l *base) updatePortStatus(listenIPPorts []string) {
  1093→	for name, p := range l.osPackages.Packages {
  1094→		if p.AffectedProcs == nil {
  1095→			continue
  1096→		}
  1097→		for i, proc := range p.AffectedProcs {
  1098→			if proc.ListenPortStats == nil {
  1099→				continue
  1100→			}
  1101→			for j, port := range proc.ListenPortStats {
  1102→				l.osPackages.Packages[name].AffectedProcs[i].ListenPortStats[j].PortReachableTo = l.findPortTestSuccessOn(listenIPPorts, port)
  1103→			}
  1104→		}
  1105→	}
  1106→}
  1107→
  1108→func (l *base) findPortTestSuccessOn(listenIPPorts []string, searchListenPort models.PortStat) []string {
  1109→	addrs := []string{}
  1110→
  1111→	for _, ipPort := range listenIPPorts {
  1112→		ipPort, err := models.NewPortStat(ipPort)
  1113→		if err != nil {
  1114→			l.log.Warnf("Failed to find: %+v", err)
  1115→			continue
  1116→		}
  1117→		if searchListenPort.BindAddress == "*" {
  1118→			if searchListenPort.Port == ipPort.Port {
  1119→				addrs = append(addrs, ipPort.BindAddress)
  1120→			}
  1121→		} else if searchListenPort.BindAddress == ipPort.BindAddress && searchListenPort.Port == ipPort.Port {
  1122→			addrs = append(addrs, ipPort.BindAddress)
  1123→		}
  1124→	}
  1125→
  1126→	return addrs
  1127→}
  1128→
  1129→func (l *base) ps() (string, error) {
  1130→	cmd := `LANGUAGE=en_US.UTF-8 ps --no-headers --ppid 2 -p 2 --deselect -o pid,comm`
  1131→	r := l.exec(util.PrependProxyEnv(cmd), noSudo)
  1132→	if !r.isSuccess() {
  1133→		return "", xerrors.Errorf("Failed to SSH: %s", r)
  1134→	}
  1135→	return r.Stdout, nil
  1136→}
  1137→
  1138→func (l *base) parsePs(stdout string) map[string]string {
  1139→	pidNames := map[string]string{}
  1140→	scanner := bufio.NewScanner(strings.NewReader(stdout))
  1141→	for scanner.Scan() {
  1142→		line := strings.TrimSpace(scanner.Text())
  1143→		ss := strings.Fields(line)
  1144→		if len(ss) < 2 {
  1145→			continue
  1146→		}
  1147→		pidNames[ss[0]] = ss[1]
  1148→	}
  1149→	return pidNames
  1150→}
  1151→
  1152→func (l *base) lsProcExe(pid string) (string, error) {
  1153→	cmd := fmt.Sprintf("ls -l /proc/%s/exe", pid)
  1154→	r := l.exec(util.PrependProxyEnv(cmd), sudo)
  1155→	if !r.isSuccess() {
  1156→		return "", xerrors.Errorf("Failed to SSH: %s", r)
  1157→	}
  1158→	return r.Stdout, nil
  1159→}
  1160→
  1161→func (l *base) parseLsProcExe(stdout string) (string, error) {
  1162→	ss := strings.Fields(stdout)
  1163→	if len(ss) < 11 {
  1164→		return "", xerrors.Errorf("Unknown format: %s", stdout)
  1165→	}
  1166→	return ss[10], nil
  1167→}
  1168→
  1169→func (l *base) grepProcMap(pid string) (string, error) {
  1170→	cmd := fmt.Sprintf(`cat /proc/%s/maps 2>/dev/null | grep -v " 00:00 " | awk '{print $6}' | sort -n | uniq`, pid)
  1171→	r := l.exec(util.PrependProxyEnv(cmd), sudo)
  1172→	if !r.isSuccess() {
  1173→		return "", xerrors.Errorf("Failed to SSH: %s", r)
  1174→	}
  1175→	return r.Stdout, nil
  1176→}
  1177→
  1178→func (l *base) parseGrepProcMap(stdout string) (soPaths []string) {
  1179→	scanner := bufio.NewScanner(strings.NewReader(stdout))
  1180→	for scanner.Scan() {
  1181→		line := strings.TrimSpace(scanner.Text())
  1182→		line = strings.Split(line, ";")[0]
  1183→		soPaths = append(soPaths, line)
  1184→	}
  1185→	return soPaths
  1186→}
  1187→
  1188→func (l *base) lsOfListen() (string, error) {
  1189→	cmd := `lsof -i -P -n`
  1190→	r := l.exec(util.PrependProxyEnv(cmd), sudo)
  1191→	if !r.isSuccess() {
  1192→		return "", xerrors.Errorf("Failed to lsof: %s", r)
  1193→	}
  1194→	return r.Stdout, nil
  1195→}
  1196→
  1197→func (l *base) parseLsOf(stdout string) map[string][]string {
  1198→	portPids := map[string][]string{}
  1199→	scanner := bufio.NewScanner(strings.NewReader(stdout))
  1200→	for scanner.Scan() {
  1201→		line := scanner.Text()
  1202→		if !strings.Contains(line, "LISTEN") {
  1203→			continue
  1204→		}
  1205→		ss := strings.Fields(line)
  1206→		if len(ss) < 10 {
  1207→			continue
  1208→		}
  1209→		pid, ipPort := ss[1], ss[8]
  1210→		portPids[ipPort] = util.AppendIfMissing(portPids[ipPort], pid)
  1211→	}
  1212→	return portPids
  1213→}
  1214→
  1215→func (l *base) pkgPs(getOwnerPkgs func([]string) ([]string, error)) error {
  1216→	stdout, err := l.ps()
  1217→	if err != nil {
  1218→		return xerrors.Errorf("Failed to pkgPs: %w", err)
  1219→	}
  1220→	pidNames := l.parsePs(stdout)
  1221→	pidLoadedFiles := map[string][]string{}
  1222→	for pid := range pidNames {
  1223→		stdout := ""
  1224→		stdout, err = l.lsProcExe(pid)
  1225→		if err != nil {
  1226→			l.log.Debugf("Failed to exec ls -l /proc/%s/exe err: %+v", pid, err)
  1227→			continue
  1228→		}
  1229→		s, err := l.parseLsProcExe(stdout)
  1230→		if err != nil {
  1231→			l.log.Debugf("Failed to parse /proc/%s/exe: %+v", pid, err)
  1232→			continue
  1233→		}
  1234→		pidLoadedFiles[pid] = append(pidLoadedFiles[pid], s)
  1235→
  1236→		stdout, err = l.grepProcMap(pid)
  1237→		if err != nil {
  1238→			l.log.Debugf("Failed to exec /proc/%s/maps: %+v", pid, err)
  1239→			continue
  1240→		}
  1241→		ss := l.parseGrepProcMap(stdout)
  1242→		pidLoadedFiles[pid] = append(pidLoadedFiles[pid], ss...)
  1243→	}
  1244→
  1245→	pidListenPorts := map[string][]models.PortStat{}
  1246→	stdout, err = l.lsOfListen()
  1247→	if err != nil {
  1248→		// warning only, continue scanning
  1249→		l.log.Warnf("Failed to lsof: %+v", err)
  1250→	}
  1251→	portPids := l.parseLsOf(stdout)
  1252→	for ipPort, pids := range portPids {
  1253→		for _, pid := range pids {
  1254→			portStat, err := models.NewPortStat(ipPort)
  1255→			if err != nil {
  1256→				l.log.Warnf("Failed to parse ip:port: %s, err: %+v", ipPort, err)
  1257→				continue
  1258→			}
  1259→			pidListenPorts[pid] = append(pidListenPorts[pid], *portStat)
  1260→		}
  1261→	}
  1262→
  1263→	for pid, loadedFiles := range pidLoadedFiles {
  1264→		pkgNames, err := getOwnerPkgs(loadedFiles)
  1265→		if err != nil {
  1266→			l.log.Warnf("Failed to get owner pkgs of: %s", loadedFiles)
  1267→			continue
  1268→		}
  1269→		uniq := map[string]struct{}{}
  1270→		for _, name := range pkgNames {
  1271→			uniq[name] = struct{}{}
  1272→		}
  1273→
  1274→		procName := ""
  1275→		if _, ok := pidNames[pid]; ok {
  1276→			procName = pidNames[pid]
  1277→		}
  1278→		proc := models.AffectedProcess{
  1279→			PID:             pid,
  1280→			Name:            procName,
  1281→			ListenPortStats: pidListenPorts[pid],
  1282→		}
  1283→
  1284→		for name := range uniq {
  1285→			p, ok := l.Packages[name]
  1286→			if !ok {
  1287→				l.log.Warnf("Failed to find a running pkg: %s", name)
  1288→				continue
  1289→			}
  1290→			p.AffectedProcs = append(p.AffectedProcs, proc)
  1291→			l.Packages[p.Name] = p
  1292→		}
  1293→	}
  1294→	return nil
  1295→}
