   558→func (l *base) parseSystemctlStatus(stdout string) string {
   559→	scanner := bufio.NewScanner(strings.NewReader(stdout))
   560→	scanner.Scan()
   561→	line := scanner.Text()
   562→	ss := strings.Fields(line)
   563→	if len(ss) < 2 || strings.HasPrefix(line, "Failed to get unit for PID") {
   564→		return ""
   565→	}
   566→	return ss[1]
   567→}
