   859→func (l *base) detectScanDest() map[string][]string {
   860→	scanIPPortsMap := map[string][]string{}
   861→
   862→	for _, p := range l.osPackages.Packages {
   863→		if p.AffectedProcs == nil {
   864→			continue
   865→		}
   866→		for _, proc := range p.AffectedProcs {
   867→			if proc.ListenPortStats == nil {
   868→				continue
   869→			}
   870→			for _, port := range proc.ListenPortStats {
   871→				scanIPPortsMap[port.BindAddress] = append(scanIPPortsMap[port.BindAddress], port.Port)
   872→			}
   873→		}
   874→	}
   875→
   876→	scanDestIPPorts := map[string][]string{}
   877→	for addr, ports := range scanIPPortsMap {
   878→		if addr == "*" {
   879→			for _, addr := range l.ServerInfo.IPv4Addrs {
   880→				scanDestIPPorts[addr] = append(scanDestIPPorts[addr], ports...)
   881→			}
   882→		} else {
   883→			scanDestIPPorts[addr] = append(scanDestIPPorts[addr], ports...)
   884→		}
   885→	}
   886→
   887→	uniqScanDestIPPorts := map[string][]string{}
   888→	for i, scanDest := range scanDestIPPorts {
   889→		m := map[string]bool{}
   890→		for _, e := range scanDest {
   891→			if !m[e] {
   892→				m[e] = true
   893→				uniqScanDestIPPorts[i] = append(uniqScanDestIPPorts[i], e)
   894→			}
   895→		}
   896→	}
   897→
   898→	return uniqScanDestIPPorts
   899→}
   900→
   901→func (l *base) execPortsScan(scanDestIPPorts map[string][]string) ([]string, error) {
   902→	if l.getServerInfo().PortScan.IsUseExternalScanner {
   903→		listenIPPorts, err := l.execExternalPortScan(scanDestIPPorts)
   904→		if err != nil {
   905→			return []string{}, err
   906→		}
   907→		return listenIPPorts, nil
   908→	}
   909→
   910→	listenIPPorts, err := l.execNativePortScan(scanDestIPPorts)
   911→	if err != nil {
   912→		return []string{}, err
   913→	}
   914→
   915→	return listenIPPorts, nil
   916→}
   917→
   918→func (l *base) execNativePortScan(scanDestIPPorts map[string][]string) ([]string, error) {
   919→	l.log.Info("Using Port Scanner: Vuls built-in Scanner")
   920→
   921→	listenIPPorts := []string{}
   922→
   923→	for ip, ports := range scanDestIPPorts {
   924→		if !isLocalExec(l.ServerInfo.Port, l.ServerInfo.Host) && net.ParseIP(ip).IsLoopback() {
   925→			continue
   926→		}
   927→
   928→		for _, port := range ports {
   929→			scanDest := ip + ":" + port
   930→			isOpen, err := nativeScanPort(scanDest)
   931→			if err != nil {
   932→				return []string{}, err
   933→			}
   934→
   935→			if isOpen {
   936→				listenIPPorts = append(listenIPPorts, scanDest)
   937→			}
   938→		}
   939→	}
   940→
   941→	return listenIPPorts, nil
   942→}
   943→
   944→func nativeScanPort(scanDest string) (bool, error) {
   945→	conn, err := net.DialTimeout("tcp", scanDest, time.Duration(1)*time.Second)
   946→	if err != nil {
   947→		if strings.Contains(err.Error(), "i/o timeout") || strings.Contains(err.Error(), "connection refused") {
   948→			return false, nil
   949→		}
   950→		if strings.Contains(err.Error(), "too many open files") {
   951→			time.Sleep(time.Duration(1) * time.Second)
   952→			return nativeScanPort(scanDest)
   953→		}
   954→		return false, err
   955→	}
   956→	conn.Close()
   957→
   958→	return true, nil
   959→}
   960→
   961→func (l *base) execExternalPortScan(scanDestIPPorts map[string][]string) ([]string, error) {
   962→	portScanConf := l.getServerInfo().PortScan
   963→	l.log.Infof("Using Port Scanner: External Scanner(PATH: %s)", portScanConf.ScannerBinPath)
   964→	l.log.Infof("External Scanner Apply Options: Scan Techniques: %s, HasPrivileged: %t, Source Port: %s",
   965→		strings.Join(portScanConf.ScanTechniques, ","), portScanConf.HasPrivileged, portScanConf.SourcePort)
   966→	baseCmd := formatNmapOptionsToString(portScanConf)
   967→
   968→	listenIPPorts := []string{}
   969→
   970→	for ip, ports := range scanDestIPPorts {
   971→		if !isLocalExec(l.ServerInfo.Port, l.ServerInfo.Host) && net.ParseIP(ip).IsLoopback() {
   972→			continue
   973→		}
   974→
   975→		_, cancel := context.WithTimeout(context.Background(), 5*time.Minute)
   976→		defer cancel()
   977→
   978→		scanner, err := nmap.NewScanner(nmap.WithBinaryPath(portScanConf.ScannerBinPath))
   979→		if err != nil {
   980→			return []string{}, xerrors.Errorf("unable to create nmap scanner: %w", err)
   981→		}
   982→
   983→		scanTechnique, err := l.setScanTechniques()
   984→		if err != nil {
   985→			return []string{}, err
   986→		}
   987→		scanner.AddOptions(scanTechnique)
   988→
   989→		if portScanConf.HasPrivileged {
   990→			scanner.AddOptions(nmap.WithPrivileged())
   991→		} else {
   992→			scanner.AddOptions(nmap.WithUnprivileged())
   993→		}
   994→
   995→		if portScanConf.SourcePort != "" {
   996→			port, err := strconv.ParseUint(portScanConf.SourcePort, 10, 16)
   997→			if err != nil {
   998→				return []string{}, xerrors.Errorf("failed to strconv.ParseUint(%s, 10, 16) = %w", portScanConf.SourcePort, err)
   999→			}
  1000→			scanner.AddOptions(nmap.WithSourcePort(uint16(port)))
  1001→		}
  1002→
  1003→		cmd := []string{baseCmd}
  1004→		if strings.Contains(ip, ":") {
  1005→			scanner.AddOptions(nmap.WithTargets(ip[1:len(ip)-1]), nmap.WithPorts(ports...), nmap.WithIPv6Scanning())
  1006→			cmd = append(cmd, "-p", strings.Join(ports, ","), ip[1:len(ip)-1])
  1007→		} else {
  1008→			scanner.AddOptions(nmap.WithTargets(ip), nmap.WithPorts(ports...))
  1009→			cmd = append(cmd, "-p", strings.Join(ports, ","), ip)
  1010→		}
  1011→
  1012→		l.log.Debugf("Executing... %s", strings.Replace(strings.Join(cmd, " "), "\n", "", -1))
  1013→		result, warnings, err := scanner.Run()
  1014→		if err != nil {
  1015→			return []string{}, xerrors.Errorf("unable to run nmap scan: %w", err)
  1016→		}
  1017→
  1018→		if warnings != nil {
  1019→			l.log.Warnf("nmap scan warnings: %s", warnings)
  1020→		}
  1021→
  1022→		for _, host := range result.Hosts {
  1023→			if len(host.Ports) == 0 || len(host.Addresses) == 0 {
  1024→				continue
  1025→			}
  1026→
  1027→			for _, port := range host.Ports {
  1028→				if strings.Contains(string(port.Status()), string(nmap.Open)) {
  1029→					scanDest := fmt.Sprintf("%s:%d", ip, port.ID)
  1030→					listenIPPorts = append(listenIPPorts, scanDest)
  1031→				}
  1032→			}
  1033→		}
  1034→	}
  1035→
  1036→	return listenIPPorts, nil
  1037→}
