  1039→func formatNmapOptionsToString(conf *config.PortScanConf) string {
  1040→	cmd := []string{conf.ScannerBinPath}
  1041→	if len(conf.ScanTechniques) != 0 {
  1042→		for _, technique := range conf.ScanTechniques {
  1043→			cmd = append(cmd, "-"+technique)
  1044→		}
  1045→	}
  1046→
  1047→	if conf.SourcePort != "" {
  1048→		cmd = append(cmd, "--source-port "+conf.SourcePort)
  1049→	}
  1050→
  1051→	if conf.HasPrivileged {
  1052→		cmd = append(cmd, "--privileged")
  1053→	}
  1054→
  1055→	return strings.Join(cmd, " ")
  1056→}
  1057→
  1058→func (l *base) setScanTechniques() (func(*nmap.Scanner), error) {
  1059→	scanTechniques := l.getServerInfo().PortScan.GetScanTechniques()
  1060→
  1061→	if len(scanTechniques) == 0 {
  1062→		if l.getServerInfo().PortScan.HasPrivileged {
  1063→			return nmap.WithSYNScan(), nil
  1064→		}
  1065→		return nmap.WithConnectScan(), nil
  1066→	}
  1067→
  1068→	for _, technique := range scanTechniques {
  1069→		switch technique {
  1070→		case config.TCPSYN:
  1071→			return nmap.WithSYNScan(), nil
  1072→		case config.TCPConnect:
  1073→			return nmap.WithConnectScan(), nil
  1074→		case config.TCPACK:
  1075→			return nmap.WithACKScan(), nil
  1076→		case config.TCPWindow:
  1077→			return nmap.WithWindowScan(), nil
  1078→		case config.TCPMaimon:
  1079→			return nmap.WithMaimonScan(), nil
  1080→		case config.TCPNull:
  1081→			return nmap.WithTCPNullScan(), nil
  1082→		case config.TCPFIN:
  1083→			return nmap.WithTCPFINScan(), nil
  1084→		case config.TCPXmas:
  1085→			return nmap.WithTCPXmasScan(), nil
  1086→		}
  1087→	}
  1088→
  1089→	return nil, xerrors.Errorf("Failed to setScanTechniques. There is an unsupported option in ScanTechniques.")
  1090→}
  1091→
  1092→func (l *base) updatePortStatus(listenIPPorts []string) {
  1093→	for name, p := range l.osPackages.Packages {
  1094→		if p.AffectedProcs == nil {
  1095→			continue
  1096→		}
  1097→		for i, proc := range p.AffectedProcs {
  1098→			if proc.ListenPortStats == nil {
  1099→				continue
  1100→			}
  1101→			for j, port := range proc.ListenPortStats {
  1102→				l.osPackages.Packages[name].AffectedProcs[i].ListenPortStats[j].PortReachableTo = l.findPortTestSuccessOn(listenIPPorts, port)
  1103→			}
  1104→		}
  1105→	}
  1106→}
  1107→
  1108→func (l *base) findPortTestSuccessOn(listenIPPorts []string, searchListenPort models.PortStat) []string {
  1109→	addrs := []string{}
  1110→
  1111→	for _, ipPort := range listenIPPorts {
  1112→		ipPort, err := models.NewPortStat(ipPort)
  1113→		if err != nil {
  1114→			l.log.Warnf("Failed to find: %+v", err)
  1115→			continue
  1116→		}
  1117→		if searchListenPort.BindAddress == "*" {
  1118→			if searchListenPort.Port == ipPort.Port {
  1119→				addrs = append(addrs, ipPort.BindAddress)
  1120→			}
  1121→		} else if searchListenPort.BindAddress == ipPort.BindAddress && searchListenPort.Port == ipPort.Port {
  1122→			addrs = append(addrs, ipPort.BindAddress)
  1123→		}
  1124→	}
  1125→
  1126→	return addrs
  1127→}
