// testMissingPNPMEcosystem verifies that PNPM lockfiles are not detected
// because the PNPM analyzer is not imported in scanner/base.go
func testMissingPNPMEcosystem(t *testing.T) {
	// This test demonstrates that PNPM package manager is not supported
	// in the current vuls implementation

	// Create test data for PNPM lockfile
	tempDir := t.TempDir()
	pnpmLockPath := filepath.Join(tempDir, "pnpm-lock.yaml")

	pnpmContent := `lockfileVersion: 5.4
specifiers:
  express: ^4.18.0
dependencies:
  express: 4.18.1
packages:
  /express/4.18.1:
    dependencies:
      body-parser: 1.20.0
`

	if err := os.WriteFile(pnpmLockPath, []byte(pnpmContent), 0644); err != nil {
		t.Fatalf("Failed to write pnpm-lock.yaml: %v", err)
	}

	// Verify that PNPM lockfile would not be detected
	// The issue: scanner/base.go (lines 31-43) imports specific analyzers
	// but PNPM is missing from the imports. See:
	// _ "github.com/aquasecurity/fanal/analyzer/language/dotnet/nuget"
	// _ "github.com/aquasecurity/fanal/analyzer/language/nodejs/npm"
	// _ "github.com/aquasecurity/fanal/analyzer/language/nodejs/yarn"
	// But NO: _ "github.com/aquasecurity/fanal/analyzer/language/nodejs/pnpm"

	// Try to analyze the PNPM file using the current analyzer configuration
	disabledAnalyzers := []analyzer.Type{
		analyzer.TypeAlpine,
		analyzer.TypeAlma,
		analyzer.TypeAmazon,
		analyzer.TypeDebian,
		analyzer.TypePhoton,
		analyzer.TypeCentOS,
		analyzer.TypeFedora,
		analyzer.TypeOracle,
		analyzer.TypeRedHatBase,
		analyzer.TypeRocky,
		analyzer.TypeSUSE,
		analyzer.TypeUbuntu,
		analyzer.TypeApk,
		analyzer.TypeDpkg,
		analyzer.TypeRpm,
		analyzer.TypeApkCommand,
		analyzer.TypeYaml,
		analyzer.TypeTOML,
		analyzer.TypeJSON,
		analyzer.TypeDockerfile,
		analyzer.TypeHCL,
		analyzer.TypeSecret,
	}

	anal := analyzer.NewAnalyzerGroup(analyzer.GroupBuiltin, disabledAnalyzers)

	var wg semaphore.Weighted
	wg.Init(1)
	var semWg semaphore.Weighted
	semWg.Init(1)

	result := new(analyzer.AnalysisResult)

	err := anal.AnalyzeFile(
		context.Background(),
		&wg,
		&semWg,
		result,
		"",
		pnpmLockPath,
		&DummyFileInfo{size: int64(len(pnpmContent)), filemode: 0644},
		func() (dio.ReadSeekCloserAt, error) { return dio.NopCloser(bytes.NewReader([]byte(pnpmContent))), nil },
		nil,
		analyzer.AnalysisOptions{Offline: false},
	)

	if err != nil {
		t.Logf("Analysis error (expected for missing PNPM analyzer): %v", err)
	}

	// Verify no PNPM applications were detected (because PNPM analyzer is not available)
	if len(result.Applications) == 0 {
		t.Log("CONFIRMED: PNPM lockfile was not detected - PNPM analyzer is not registered")
	} else {
		pnpmDetected := false
		for _, app := range result.Applications {
			if app.Type == types.Pnpm {
				pnpmDetected = true
				break
			}
		}
		if !pnpmDetected {
			t.Log("CONFIRMED: PNPM was not detected among applications")
		}
	}
}

