// testMissingPNPMEcosystem verifies that PNPM lockfiles are not detected
// because the PNPM analyzer is not imported in scanner/base.go (lines 31-43)
func testMissingPNPMEcosystem(t *testing.T) {
	// Issue: PNPM is not imported in scanner/base.go
	// Current imports (lines 31-43):
	// - nuget (line 31)
	// - golang binary (line 32)
	// - golang mod (line 33)
	// - java jar (line 34)
	// - java pom (line 35)
	// - nodejs npm (line 36)
	// - nodejs yarn (line 37)
	// - composer (line 38)
	// - python pip (line 39)
	// - python pipenv (line 40)
	// - python poetry (line 41)
	// - ruby bundler (line 42)
	// - rust cargo (line 43)
	// Missing: PNPM

	tempDir := t.TempDir()
	pnpmLockPath := filepath.Join(tempDir, "pnpm-lock.yaml")

	pnpmContent := `lockfileVersion: 5.4
specifiers:
  express: ^4.18.0
dependencies:
  express: 4.18.1
packages:
  /express/4.18.1:
    dependencies:
      body-parser: 1.20.0
`

	if err := os.WriteFile(pnpmLockPath, []byte(pnpmContent), 0644); err != nil {
		t.Fatalf("Failed to write pnpm-lock.yaml: %v", err)
	}

	// Create analyzer group with disabled non-library analyzers
	// This mimics what scanner/base.go does (line 690)
	disabledAnalyzers := []analyzer.Type{
		analyzer.TypeAlpine,
		analyzer.TypeAlma,
		analyzer.TypeAmazon,
		analyzer.TypeDebian,
		analyzer.TypePhoton,
		analyzer.TypeCentOS,
		analyzer.TypeFedora,
		analyzer.TypeOracle,
		analyzer.TypeRedHatBase,
		analyzer.TypeRocky,
		analyzer.TypeSUSE,
		analyzer.TypeUbuntu,
		analyzer.TypeApk,
		analyzer.TypeDpkg,
		analyzer.TypeRpm,
		analyzer.TypeApkCommand,
		analyzer.TypeYaml,
		analyzer.TypeTOML,
		analyzer.TypeJSON,
		analyzer.TypeDockerfile,
		analyzer.TypeHCL,
		analyzer.TypeSecret,
	}

	anal := analyzer.NewAnalyzerGroup(analyzer.GroupBuiltin, disabledAnalyzers)

	var wg sync.WaitGroup
	semWg := semaphore.NewWeighted(1)

	result := new(analyzer.AnalysisResult)

	err := anal.AnalyzeFile(
		context.Background(),
		&wg,
		semWg,
		result,
		"",
		pnpmLockPath,
		&DummyFileInfo{size: int64(len(pnpmContent)), filemode: 0644},
		func() (dio.ReadSeekCloserAt, error) { return dio.NopCloser(bytes.NewReader([]byte(pnpmContent))), nil },
		nil,
		analyzer.AnalysisOptions{Offline: false},
	)

	if err != nil {
		t.Logf("Analysis error (expected - PNPM analyzer not registered): %v", err)
	}

	// Verify that PNPM was not detected
	pnpmDetected := false
	for _, app := range result.Applications {
		// Check for PNPM type (would be "pnpm" as string)
		appTypeStr := string(app.Type)
		if appTypeStr == "pnpm" {
			pnpmDetected = true
			t.Logf("ERROR: PNPM should not be detected, but found: %s", app.Type)
			break
		}
	}

	if !pnpmDetected {
		t.Log("CONFIRMED: PNPM lockfile was not detected - PNPM analyzer is not registered")
	}
}

